const upload = require('../src/upload');
const fs = require('fs');
const path = require('path');

describe('File Upload', () => {
  test('should process file upload', async () => {
    const file = {name: 'test.txt', data: Buffer.from('test content')};
    const result = await upload.processFile(file);

    expect(result.success).toBe(true);
    expect(result.path).toBeDefined();
    expect(fs.existsSync(result.path)).toBe(true);
  });

  test('should validate file size', async () => {
    const largeFile = {name: 'large.txt', data: Buffer.alloc(11 * 1024 * 1024)};
    await expect(upload.processFile(largeFile)).rejects.toThrow('File too large');
  });

  test('should clean up temp files', async () => {
    const tempDir = path.join(__dirname, '../temp');
    const files = fs.readdirSync(tempDir);
    expect(files.length).toBe(0);
  });
});

